item.description:
 &lt;h1 id=&#34;1、aria2开机启动文件配置—aria2-service&#34;&gt;&lt;a href=&#34;#1、aria2开机启动文件配置—aria2-service&#34; class=&#34;headerlink&#34; title=&#34;1、aria2开机启动文件配置—aria2.service&#34;&gt;&lt;/a&gt;1、aria2开机启动文件配置—&lt;code&gt;aria2.service&lt;/code&gt;&lt;/h1&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;k@yk-pc:~$ sudo nano /usr/lib/systemd/system/aria2.service&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;输入以下内容：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[Unit]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Description=Aria2 Service&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;After=network.target&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Service]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ExecStart=/usr/bin/aria2c --conf-path=/etc/aria2/aria2.conf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[Install]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;WantedBy=default.target&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;写入&lt;code&gt;ctrl+o&lt;/code&gt;，保存 &lt;code&gt;Enter&lt;/code&gt;，退出&lt;code&gt;ctrl+x&lt;/code&gt;&lt;br&gt;拷贝到&lt;code&gt;/etc/systemd/user&lt;/code&gt; 目录下&lt;br&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;k@yk-pc:~$ sudo cp /usr/lib/systemd/system/aria2.service /etc/systemd/system&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h1 id=&#34;2-设置开机启动&#34;&gt;&lt;a href=&#34;#2-设置开机启动&#34; class=&#34;headerlink&#34; title=&#34;2.设置开机启动&#34;&gt;&lt;/a&gt;2.设置开机启动&lt;/h1&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;yk@yk-pc:/usr/lib/systemd/system$ systemctl &lt;span class=&#34;built_in&#34;&gt;enable&lt;/span&gt; aria2.service&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;提示&lt;code&gt;Created symlink /etc/systemd/system/default.target.wants/aria2.service → /etc/systemd/system/aria2.service.&lt;/code&gt;设置成功&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://github.com/P3TERX/aria2.conf&#34;&gt;一键安装及配置开源项目：&lt;/a&gt;&lt;/p&gt;

 &lt;h1 id=&#34;写在前面&#34;&gt;&lt;a href=&#34;#写在前面&#34; class=&#34;headerlink&#34; title=&#34;写在前面&#34;&gt;&lt;/a&gt;写在前面&lt;/h1&gt;&lt;p&gt;&lt;a href=&#34;https://www.youtube-dl.org/&#34;&gt;youtube-dl官网：&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://github.com/ytdl-org/youtube-dl/releases&#34;&gt;youtube-dl最新发布版本下载地址：&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://github.com/aria2/aria2&#34;&gt;aria2项目：&lt;/a&gt;&lt;br&gt;&lt;a href=&#34;https://github.com/aria2/aria2&#34;&gt;aria2最新发布版本下载地址：&lt;/a&gt;  &lt;/p&gt;
&lt;h1 id=&#34;1、基本用法&#34;&gt;&lt;a href=&#34;#1、基本用法&#34; class=&#34;headerlink&#34; title=&#34;1、基本用法&#34;&gt;&lt;/a&gt;1、基本用法&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl &lt;span class=&#34;string&#34;&gt;&amp;quot;视频文件网络路径&amp;quot;&lt;/span&gt;  --external-downloader aria2c --external-downloader-args &lt;span class=&#34;string&#34;&gt;&amp;quot;-x 16 -k 1M&amp;quot;&lt;/span&gt; -o f:/yz3.mp4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;参数说明：&lt;br&gt;&lt;code&gt;--external-downloader aria2c&lt;/code&gt; //调用外部下载工具&lt;br&gt;&lt;code&gt;--external-downloader-args&lt;/code&gt; //外部下载工具指定参数&lt;br&gt;&lt;code&gt;-x 16&lt;/code&gt; //启用aria2 16个线程，最多就支持16线程&lt;br&gt;&lt;code&gt;-k 1M&lt;/code&gt; //指定块的大小&lt;br&gt;代理&lt;br&gt;&lt;code&gt;--proxy &amp;quot;https://127.0.0.1:1080&amp;quot;&lt;/code&gt;&lt;br&gt;  //或者直接这样&lt;br&gt;  &lt;code&gt;--proxy 127.0.0.1:1080&lt;/code&gt;&lt;/p&gt;
&lt;h1 id=&#34;2、下载视频列表&#34;&gt;&lt;a href=&#34;#2、下载视频列表&#34; class=&#34;headerlink&#34; title=&#34;2、下载视频列表&#34;&gt;&lt;/a&gt;2、下载视频列表&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl [playlist_url] //下载视频列表,这种方式下载的视频可能是mkv格式或者webm格式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl -cit [playlist_url] //下载视频列表,这种方式下载的视频可能是mkv格式或者webm格式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl --yes-playlist [url] //当链接为视频列表,则下载该列表视频,跟上面的一样,可能是mkv或者webm格式&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;3、下载字幕&#34;&gt;&lt;a href=&#34;#3、下载字幕&#34; class=&#34;headerlink&#34; title=&#34;3、下载字幕&#34;&gt;&lt;/a&gt;3、下载字幕&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl --write-sub --skip-download [url] //下载单独的vtt字幕文件,而不会下载视频&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl --write-sub --all-subs [url] //下载所有语言的字幕(如果有的话)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl --write-auto-sub [url] //下载自动生成的字幕(YouTube only)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;4、查看视频所有类型-只看不下载&#34;&gt;&lt;a href=&#34;#4、查看视频所有类型-只看不下载&#34; class=&#34;headerlink&#34; title=&#34;4、查看视频所有类型,只看不下载&#34;&gt;&lt;/a&gt;4、查看视频所有类型,只看不下载&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl -F &lt;span class=&#34;string&#34;&gt;&amp;quot;视频文件网络路径&amp;quot;&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;5、下载指定质量的视频和音频并自动合并&#34;&gt;&lt;a href=&#34;#5、下载指定质量的视频和音频并自动合并&#34; class=&#34;headerlink&#34; title=&#34;5、下载指定质量的视频和音频并自动合并&#34;&gt;&lt;/a&gt;5、下载指定质量的视频和音频并自动合并&lt;/h1&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl -f [format code] [url]   //format code :视频+音频如：137+140&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;format code  extension  resolution note&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;249          webm       audio only tiny   67k , opus @ 50k (48000Hz), 9.10MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;250          webm       audio only tiny   86k , opus @ 70k (48000Hz), 11.77MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;140          m4a        audio only tiny  131k , m4a_dash container, mp4a.40.2@128k (44100Hz), 22.87MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;251          webm       audio only tiny  157k , opus @160k (48000Hz), 22.30MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;394          mp4        256x144    144p   84k , av01.0.00M.08, 25fps, video only, 11.84MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;278          webm       256x144    144p   97k , webm container, vp9, 25fps, video only, 14.93MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;160          mp4        256x144    144p  124k , avc1.4d400c, 25fps, video only, 13.26MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;395          mp4        426x240    240p  182k , av01.0.00M.08, 25fps, video only, 22.28MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;242          webm       426x240    240p  225k , vp9, 25fps, video only, 25.68MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;133          mp4        426x240    240p  275k , avc1.4d4015, 25fps, video only, 21.26MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;396          mp4        640x360    360p  379k , av01.0.01M.08, 25fps, video only, 41.58MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;243          webm       640x360    360p  411k , vp9, 25fps, video only, 42.61MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;134          mp4        640x360    360p  521k , avc1.4d401e, 25fps, video only, 36.68MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;397          mp4        854x480    480p  661k , av01.0.04M.08, 25fps, video only, 68.76MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;244          webm       854x480    480p  759k , vp9, 25fps, video only, 61.26MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;135          mp4        854x480    480p  922k , avc1.4d401e, 25fps, video only, 52.38MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;398          mp4        1280x720   720p 1255k , av01.0.05M.08, 25fps, video only, 123.54MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;247          webm       1280x720   720p 1432k , vp9, 25fps, video only, 97.51MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;136          mp4        1280x720   720p 1561k , avc1.4d401f, 25fps, video only, 86.93MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;399          mp4        1920x1080  1080p 2244k , av01.0.08M.08, 25fps, video only, 212.73MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;248          webm       1920x1080  1080p 2645k , vp9, 25fps, video only, 244.97MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;137          mp4        1920x1080  1080p 4023k , avc1.640028, 25fps, video only, 253.08MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18           mp4        640x360    360p  503k , avc1.42001E, 25fps, mp4a.40.2@ 96k (44100Hz), 88.99MiB&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22           mp4        1280x720   720p  621k , avc1.64001F, 25fps, mp4a.40.2@192k (44100Hz) (best)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h1 id=&#34;6、批量下载&#34;&gt;&lt;a href=&#34;#6、批量下载&#34; class=&#34;headerlink&#34; title=&#34;6、批量下载&#34;&gt;&lt;/a&gt;6、批量下载&lt;/h1&gt;&lt;h2 id=&#34;①各个视频地址列表下载&#34;&gt;&lt;a href=&#34;#①各个视频地址列表下载&#34; class=&#34;headerlink&#34; title=&#34;①各个视频地址列表下载&#34;&gt;&lt;/a&gt;①各个视频地址列表下载&lt;/h2&gt;&lt;p&gt;命令：&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl -f 22 -a list.txt&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;其中&lt;code&gt;list.txt&lt;/code&gt; 的 &lt;code&gt;text&lt;/code&gt;文件格式&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;https://www.youtube.com/watch?v=*****&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;https://www.youtube.com/watch?v=*****&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;https://www.youtube.com/watch?v=*****&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;②批量下载“播放列表”的视频&#34;&gt;&lt;a href=&#34;#②批量下载“播放列表”的视频&#34; class=&#34;headerlink&#34; title=&#34;②批量下载“播放列表”的视频&#34;&gt;&lt;/a&gt;②批量下载“播放列表”的视频&lt;/h2&gt;&lt;p&gt;格式:&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;https://www.youtube.com/playlist?list=&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;Ⅰ&amp;gt;下载列表中指定连续的内容(比如：&lt;code&gt;--playlist-start 1 --playlist-end 27&lt;/code&gt;)&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl -f 22 -ci --playlist-start 1 --playlist-end 24 &lt;span class=&#34;string&#34;&gt;&amp;quot;https://www.youtube.com/playlist?list=*****&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;Ⅱ&amp;gt;下载列表中指定的不连续内容(比如：&lt;code&gt;--playlist-items 1,3-5,7, 21-27&lt;/code&gt;)&lt;br&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;youtube-dl -f 22 -ci --playlist-items 1,3-5,7, 21-27 &lt;span class=&#34;string&#34;&gt;&amp;quot;https://www.youtube.com/playlist?list=*******&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h1 id=&#34;7、ffmpeg-合并视频&#34;&gt;&lt;a href=&#34;#7、ffmpeg-合并视频&#34; class=&#34;headerlink&#34; title=&#34;7、ffmpeg 合并视频&#34;&gt;&lt;/a&gt;7、ffmpeg 合并视频&lt;/h1&gt;&lt;h2 id=&#34;①命令1：&#34;&gt;&lt;a href=&#34;#①命令1：&#34; class=&#34;headerlink&#34; title=&#34;①命令1：&#34;&gt;&lt;/a&gt;①命令1：&lt;/h2&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ffmpeg -i &lt;span class=&#34;string&#34;&gt;&amp;quot;concat:yz1.mp4|yz2.mp4|yz3.mp4|yz4.mp4|yz5.mp4|yz6.mp4|yz7.mp4|yz8.mp4|yz9.mp4|yz10.mp4|&amp;quot;&lt;/span&gt; -c copy output.mp4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;②命令2：&#34;&gt;&lt;a href=&#34;#②命令2：&#34; class=&#34;headerlink&#34; title=&#34;②命令2：&#34;&gt;&lt;/a&gt;②命令2：&lt;/h2&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ffmpeg -f concat -safe 0 -i filelist.txt -c copy output.mp4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;其中：&lt;code&gt;filelist.txt&lt;/code&gt;&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz1.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz2.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz3.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz4.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz5.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz6.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz7.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz8.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz9.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;file  &amp;#x27;F:\yz10.mp4&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h2 id=&#34;8、ffmpeg操作字母&#34;&gt;&lt;a href=&#34;#8、ffmpeg操作字母&#34; class=&#34;headerlink&#34; title=&#34;8、ffmpeg操作字母&#34;&gt;&lt;/a&gt;8、ffmpeg操作字母&lt;/h2&gt;&lt;h3 id=&#34;1-gt-字母相互转换&#34;&gt;&lt;a href=&#34;#1-gt-字母相互转换&#34; class=&#34;headerlink&#34; title=&#34;1&amp;gt;字母相互转换&#34;&gt;&lt;/a&gt;1&amp;gt;字母相互转换&lt;/h3&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ffmpeg -i input.vtt output.srt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ffmpeg -i input.srt output.ass&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2-gt-把字幕压制到视频&#34;&gt;&lt;a href=&#34;#2-gt-把字幕压制到视频&#34; class=&#34;headerlink&#34; title=&#34;2&amp;gt;把字幕压制到视频&#34;&gt;&lt;/a&gt;2&amp;gt;把字幕压制到视频&lt;/h3&gt;&lt;figure class=&#34;highlight sh&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ffmpeg -i input.mp4 -vf ass=subtitle.ass output.mp4  &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;em&gt;注意&lt;code&gt;win&lt;/code&gt;下&lt;code&gt;ass=subtitle.ass&lt;/code&gt;不能使用盘符，可使用相对路径&lt;/em&gt;&lt;/p&gt;

 &lt;h2 id=&#34;【【【【千万注意配置文件中勿用中文标点符号】】】】&#34;&gt;&lt;a href=&#34;#【【【【千万注意配置文件中勿用中文标点符号】】】】&#34; class=&#34;headerlink&#34; title=&#34;【【【【千万注意配置文件中勿用中文标点符号】】】】&#34;&gt;&lt;/a&gt;&lt;strong&gt;【【【【千万注意配置文件中勿用中文标点符号】】】】&lt;/strong&gt;&lt;/h2&gt;&lt;p&gt;3211版本注册码：&lt;br&gt;&lt;code&gt;请自寻搜索&lt;/code&gt;&lt;/p&gt;
&lt;h3 id=&#34;一、安装插件安装控制-键ctrl&#34;&gt;&lt;a href=&#34;#一、安装插件安装控制-键ctrl&#34; class=&#34;headerlink&#34; title=&#34;一、安装插件安装控制 键ctrl+`&#34;&gt;&lt;/a&gt;一、安装插件安装控制 键ctrl+`&lt;/h3&gt;&lt;figure class=&#34;highlight python&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; urllib.request,os,hashlib; h = &lt;span class=&#34;string&#34;&gt;&amp;#x27;6f4c264a24d933ce70df5dedcf1dcaee&amp;#x27;&lt;/span&gt; + &lt;span class=&#34;string&#34;&gt;&amp;#x27;ebe013ee18cced0ef93d5f746d80ef60&amp;#x27;&lt;/span&gt;; pf = &lt;span class=&#34;string&#34;&gt;&amp;#x27;Package Control.sublime-package&amp;#x27;&lt;/span&gt;; ipp = sublime.installed_packages_path(); urllib.request.install_opener( urllib.request.build_opener( urllib.request.ProxyHandler()) ); by = urllib.request.urlopen( &lt;span class=&#34;string&#34;&gt;&amp;#x27;http://packagecontrol.io/&amp;#x27;&lt;/span&gt; + pf.replace(&lt;span class=&#34;string&#34;&gt;&amp;#x27; &amp;#x27;&lt;/span&gt;, &lt;span class=&#34;string&#34;&gt;&amp;#x27;%20&amp;#x27;&lt;/span&gt;)).read(); dh = hashlib.sha256(by).hexdigest(); &lt;span class=&#34;built_in&#34;&gt;print&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;Error validating download (got %s instead of %s), please try manual install&amp;#x27;&lt;/span&gt; % (dh, h)) &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; dh != h &lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;built_in&#34;&gt;open&lt;/span&gt;(os.path.join( ipp, pf), &lt;span class=&#34;string&#34;&gt;&amp;#x27;wb&amp;#x27;&lt;/span&gt; ).write(by)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;二、安装SublimeTmpl-模板插件&#34;&gt;&lt;a href=&#34;#二、安装SublimeTmpl-模板插件&#34; class=&#34;headerlink&#34; title=&#34;二、安装SublimeTmpl 模板插件&#34;&gt;&lt;/a&gt;二、安装SublimeTmpl 模板插件&lt;/h3&gt;&lt;ol&gt;
&lt;li&gt;ctrl+alt+h html5模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+j js模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+c css模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+p php模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+r ruby模板 &lt;/li&gt;
&lt;li&gt;ctrl+alt+shift+p python模板 &lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;三、sublimeSideBar插件&#34;&gt;&lt;a href=&#34;#三、sublimeSideBar插件&#34; class=&#34;headerlink&#34; title=&#34;三、sublimeSideBar插件&#34;&gt;&lt;/a&gt;三、sublimeSideBar插件&lt;/h3&gt;&lt;p&gt;sublime text 3 localhost 配置 &lt;/p&gt;
&lt;h4 id=&#34;1-安装侧边栏增强插件&#34;&gt;&lt;a href=&#34;#1-安装侧边栏增强插件&#34; class=&#34;headerlink&#34; title=&#34;1. 安装侧边栏增强插件&#34;&gt;&lt;/a&gt;1. 安装侧边栏增强插件&lt;/h4&gt;&lt;p&gt;在 Sublime Text 3 中，安装 &lt;code&gt;SideBarEnhancements&lt;/code&gt; 侧边栏增强插件。 &lt;/p&gt;
&lt;h4 id=&#34;2-配置SideBarEnhancements-插件&#34;&gt;&lt;a href=&#34;#2-配置SideBarEnhancements-插件&#34; class=&#34;headerlink&#34; title=&#34;2. 配置SideBarEnhancements 插件&#34;&gt;&lt;/a&gt;2. 配置&lt;code&gt;SideBarEnhancements&lt;/code&gt; 插件&lt;/h4&gt;&lt;p&gt;&lt;code&gt;SideBarEnhancements&lt;/code&gt; 插件安装完成后，首先为 &lt;code&gt;SideBarEnhancements&lt;/code&gt; 指定默认浏览器。【见4】&lt;/p&gt;
&lt;h4 id=&#34;3-配置php环境&#34;&gt;&lt;a href=&#34;#3-配置php环境&#34; class=&#34;headerlink&#34; title=&#34;3. 配置php环境&#34;&gt;&lt;/a&gt;3. 配置php环境&lt;/h4&gt;&lt;p&gt;工具—-系统编译—-新编译系统 替换内容为 【配置php环境】&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    cmd: [php, $file],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    file_regex: php$,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    selector: source.php&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;另存文件—文件夹默认—文件名 &lt;code&gt;php.sublime-build&lt;/code&gt; &lt;/p&gt;
&lt;h4 id=&#34;4-指定默认浏览器&#34;&gt;&lt;a href=&#34;#4-指定默认浏览器&#34; class=&#34;headerlink&#34; title=&#34;4. 指定默认浏览器&#34;&gt;&lt;/a&gt;4. 指定默认浏览器&lt;/h4&gt;&lt;p&gt;打开 &lt;code&gt;Preference --&amp;gt; Package Settings --&amp;gt; Side Bar --&amp;gt; Settings User-User&lt;/code&gt;&lt;br&gt;【如果在热键绑定 browser: chrome中设置，在此可以不设置，即省略此步】&lt;br&gt;//单浏览器预览本地服务器url&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  default_browser: chrome &lt;span class=&#34;comment&#34;&gt;//one of this list: firefox, aurora, chrome, canary, chromium, opera, safari&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;//多浏览器预览本地服务器url&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;open_all_browsers: [&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        firefox,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        firefox-developer-edition,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        chrome,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        opera,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        safari,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ie,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        edge&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ],&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;5-指定默认localhsot目录&#34;&gt;&lt;a href=&#34;#5-指定默认localhsot目录&#34; class=&#34;headerlink&#34; title=&#34;5. 指定默认localhsot目录&#34;&gt;&lt;/a&gt;5. 指定默认localhsot目录&lt;/h4&gt;&lt;p&gt;为 SideBarEnhancements 指定默认localhsot目录。 在侧边栏任意文档上点击鼠标右键，选择 &lt;code&gt;Project --&amp;gt; Edit Preview URLs&lt;/code&gt; 【多站点配置】【文件名&lt;code&gt;SideBarEnhancements.json&lt;/code&gt;】&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    F:\\php:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_testing: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8090/,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_production: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8090/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    F:\\WebSite:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_testing: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8081/,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_production: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8081/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    F:/asp/siteserver_install:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_testing: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8080/,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        url_production: http:&lt;span class=&#34;comment&#34;&gt;//localhost:8080/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;6、热键绑定&#34;&gt;&lt;a href=&#34;#6、热键绑定&#34; class=&#34;headerlink&#34; title=&#34;6、热键绑定&#34;&gt;&lt;/a&gt;6、热键绑定&lt;/h4&gt;&lt;p&gt;打开 &lt;code&gt;Preference&lt;/code&gt; —&amp;gt; &lt;code&gt;Package Settings&lt;/code&gt; —&amp;gt; &lt;code&gt;Side Bar&lt;/code&gt; —&amp;gt; &lt;code&gt;key Bindings-User&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/s